import { Component, Event, EventEmitter, Prop, h } from '@stencil/core';
import type { FiscalDocumentFilters, FiscalFilterType } from '../types';
import WaOption from '@awesome.me/webawesome/dist/components/option/option';

@Component({
  tag: 'ir-city-ledger-fiscal-documents-filters',
  styleUrl: 'ir-city-ledger-fiscal-documents-filters.css',
  scoped: true,
})
export class IrCityLedgerFiscalDocumentsFilters {
  @Prop() filters: FiscalDocumentFilters = {
    fromDate: null,
    toDate: null,
    docNumber: '',
    taxableOnly: false,
    type: 'all',
  };

  @Event() filtersChange: EventEmitter<FiscalDocumentFilters>;

  private typeOptions: Array<{ label: string; value: FiscalFilterType }> = [
    { label: 'All Document Types', value: 'all' },
    { label: 'Invoices', value: 'invoice' },
    { label: 'Receipts', value: 'receipt' },
    { label: 'Credit Notes', value: 'credit-note' },
    { label: 'Debit Notes', value: 'debit-note' },
  ];

  private updateFilters(patch: Partial<FiscalDocumentFilters>) {
    this.filtersChange.emit({
      ...this.filters,
      ...patch,
    });
  }

  render() {
    return (
      <section class="fiscal-filters" aria-label="Fiscal document filters">
        <div class="fiscal-filters__left">
          <ir-date-range-filter
            class="fiscal-filters__dates"
            fromDate={this.filters.fromDate}
            toDate={this.filters.toDate}
            onDatesChanged={e => this.updateFilters({ fromDate: e.detail.from, toDate: e.detail.to })}
          ></ir-date-range-filter>
          <wa-select
            value={this.filters.type}
            defaultValue={this.filters.type}
            onchange={e => this.updateFilters({ type: (e.target as WaOption).value as any })}
            size="small"
            placeholder="Status"
          >
            {this.typeOptions.map(option => (
              <wa-option value={option.value} key={option.value}>
                {option.label}
              </wa-option>
            ))}
          </wa-select>
          <ir-input placeholder="Search" class="fiscal-filters__search">
            <wa-icon name="magnifying-glass" slot="start"></wa-icon>
          </ir-input>

          <wa-switch id="tax-switch" checked={this.filters.taxableOnly} onchange={event => this.updateFilters({ taxableOnly: (event.target as HTMLInputElement).checked })}>
            Taxes
          </wa-switch>
        </div>
      </section>
    );
  }
}
