import { Component, Event, EventEmitter, Fragment, Prop, State, Watch, h } from '@stencil/core';
import moment from 'moment';
import type { ZodIssue } from 'zod';
import type { IEntries } from '@/models/IBooking';
import type { PaymentEntries } from '@/components/ir-booking-details/types';
import { BookingService } from '@/services/booking-service/booking.service';
import { buildPaymentTypes } from '@/services/booking-service/utils';
import { CityLedgerService } from '@/services/city-ledger';
import calendar_data from '@/stores/calendar-data';
import {
  DATE_INPUT_FORMAT,
  LINK_TYPES,
  amountFieldSchema,
  createInitialTransactionFormDraft,
  dateFieldSchema,
  entryTypeFieldSchema,
  invoiceIdRequiredFieldSchema,
  linkTypeFieldSchema,
  paymentMethodCodeFieldSchema,
  resetDraftForTransactionType,
  taxIdFieldSchema,
  transactionTypeFieldSchema,
  validateCityLedgerTransaction,
  type CityLedgerTransactionFormDraft,
  type CityLedgerTransactionPayload,
  type EntryType,
  type LinkedOption,
  type LinkType,
  type ServiceCategoryOption,
  type TaxOption,
  type TransactionType,
  TRANSACTION_TYPE_RATES,
} from './ir-city-ledger-transaction-form.schema';
import { getEntryValue } from '@/utils/utils';

@Component({
  tag: 'ir-city-ledger-transaction-form',
  styleUrl: 'ir-city-ledger-transaction-form.css',
  scoped: true,
})
export class IrCityLedgerTransactionForm {
  @Prop() formId: string = 'city-ledger-transaction-form';
  @Prop() agentId: number | null = null;
  @Prop() initialTransactionType: TransactionType = 'OB';
  @Prop() taxOptions: TaxOption[] = [];
  @Prop() unpaidInvoiceOptions: LinkedOption[] = [];
  @Prop() bookingOptions: LinkedOption[] = [];
  @Prop() serviceCategoryOptions: ServiceCategoryOption[] = [];
  @Prop() currencySymbol: string = '$';
  @Prop() language: string = 'en';

  @State() formData: CityLedgerTransactionFormDraft = createInitialTransactionFormDraft();
  @State() paymentEntries: PaymentEntries = {
    types: [],
    groups: [],
    methods: [],
  };
  @State() paymentTypeGroups: Record<string, IEntries[]> = {};
  @State() isLoading: boolean = true;
  @State() isSubmitting: boolean = false;

  @Event() transactionSaved: EventEmitter<void>;
  @Event() transactionValidationFailed: EventEmitter<ZodIssue[]>;

  private bookingService = new BookingService();
  private cityLedgerService = new CityLedgerService();
  private clTxTypes: IEntries[];

  componentWillLoad() {
    this.formData = createInitialTransactionFormDraft(this.initialTransactionType);
    this.fetchPaymentEntries();
  }

  @Watch('initialTransactionType')
  handleInitialTransactionTypeChange(newType: TransactionType) {
    this.formData = resetDraftForTransactionType(newType, this.formData);
  }

  private updateFormData(patch: Partial<CityLedgerTransactionFormDraft>) {
    this.formData = {
      ...this.formData,
      ...patch,
    };
  }

  private handleTransactionTypeChange(nextType: TransactionType) {
    this.formData = resetDraftForTransactionType(nextType, this.formData);
  }

  private async fetchPaymentEntries() {
    try {
      this.isLoading = true;
      const setupEntries = await this.bookingService.getSetupEntriesByTableNameMulti(['_PAY_TYPE', '_PAY_TYPE_GROUP', '_PAY_METHOD', '_CL_TX_TYPE']);
      const { pay_type, pay_type_group, pay_method, cl_tx_type } = this.bookingService.groupEntryTablesResult(setupEntries);
      this.paymentEntries = {
        types: pay_type ?? [],
        groups: pay_type_group ?? [],
        methods: pay_method ?? [],
      };
      this.clTxTypes = cl_tx_type;
      this.paymentTypeGroups = buildPaymentTypes(this.paymentEntries);
    } catch (error) {
      console.error('Failed to load payment setup entries', error);
      this.paymentEntries = { types: [], groups: [], methods: [] };
      this.paymentTypeGroups = {};
    } finally {
      this.isLoading = false;
    }
  }

  private stopEventPropagation(event: Event) {
    event.stopImmediatePropagation();
    event.stopPropagation();
  }

  private handlePaymentMethodDropdownChange(value: string) {
    const paymentMethod = this.paymentEntries?.methods?.find(pm => pm.CODE_NAME === value);
    if (!paymentMethod) {
      this.updateFormData({ payment_method: null });
      return;
    }
    this.updateFormData({
      payment_method: {
        code: paymentMethod.CODE_NAME,
        description: paymentMethod.CODE_VALUE_EN,
        operation: paymentMethod.NOTES,
      },
    });
  }

  private buildParams(payload: CityLedgerTransactionPayload) {
    const amount = payload.amount;
    let credit = 0;
    let debit = 0;
    let payMethodCode = '';

    switch (payload.transactionType) {
      case 'OB':
      case 'ADJ':
        if (payload.entryType === 'CR') credit = amount;
        else debit = amount;
        break;
      case 'PAY':
      case 'CN':
        credit = amount;
        break;
      case 'DB':
      case 'DN':
        debit = amount;
        break;
    }

    if (payload.transactionType === 'PAY') {
      payMethodCode = payload.payment_method?.code ?? '';
    }

    const noTaxTransaction = payload.transactionType === 'OB' || payload.transactionType === 'PAY';
    const hasVat = !noTaxTransaction && payload.taxId !== 'N/A';

    return {
      CL_TX_ID: -1,
      AGENCY_ID: this.agentId,
      SERVICE_DATE: payload.date,
      // CATEGORY: payload.transactionType,
      CL_TX_TYPE_CODE: payload.transactionType,
      DESCRIPTION: payload.reference ?? payload.transactionType,
      DEBIT: debit,
      CREDIT: credit,
      CURRENCY_ID: calendar_data?.property?.currency?.id,
      PAY_METHOD_CODE: payMethodCode,
      EXTERNAL_REF: payload.reference ?? '',
      VAT_INCLUDED_CODE: (noTaxTransaction ? '' : hasVat ? '001' : '002') as '001' | '002',
      VAT_PCT: noTaxTransaction ? null : hasVat ? Number(payload.taxId) : 0,
    };
  }

  private handleSubmit = async (event: Event) => {
    event.preventDefault();
    const validation = validateCityLedgerTransaction(this.formData);

    if (!validation.success) {
      this.transactionValidationFailed.emit(validation.error.issues);
      return;
    }

    try {
      this.isSubmitting = true;
      await this.cityLedgerService.issueManualCLTx(this.buildParams(validation.data));
      this.transactionSaved.emit();
    } catch (error) {
      console.error('Failed to save transaction', error);
    } finally {
      this.isSubmitting = false;
    }
  };

  private get linkedIdOptions(): LinkedOption[] {
    if (this.formData.linkType === 'BOOKING') {
      return this.bookingOptions;
    }
    if (this.formData.linkType === 'INVOICE') {
      return this.unpaidInvoiceOptions;
    }
    return [];
  }

  private renderCommonFields(withTaxes: boolean = true) {
    const minAllowedDate = moment().subtract(1, 'months').format(DATE_INPUT_FORMAT);

    return (
      <Fragment>
        <div class="transaction-form__field">
          <ir-validator schema={transactionTypeFieldSchema} value={this.formData.transactionType} valueEvent="change">
            <wa-select
              label="Transaction Type"
              size="small"
              defaultValue={this.formData.transactionType}
              value={this.formData.transactionType}
              required
              onchange={event => {
                const value = (event.target as HTMLSelectElement).value as TransactionType;
                this.handleTransactionTypeChange(value);
              }}
            >
              {this.clTxTypes.map(type => {
                const rate = TRANSACTION_TYPE_RATES[type.CODE_NAME];
                const label = type.CODE_VALUE_EN;
                return (
                  <wa-option key={type.CODE_NAME} value={type.CODE_NAME} label={label}>
                    <div class="tx-option">
                      <span class="tx-option__label">{label}</span>
                      <span class="tx-option__badges">
                        {(rate === 'CR' || rate === 'CR|DB') && <wa-badge variant="success">Credit</wa-badge>}
                        {(rate === 'DB' || rate === 'CR|DB') && <wa-badge variant="danger">Debit</wa-badge>}
                      </span>
                    </div>
                  </wa-option>
                );
              })}
            </wa-select>
          </ir-validator>
        </div>

        <div class="transaction-form__field">
          <ir-validator schema={dateFieldSchema} value={this.formData.date} valueEvent="DateChanged">
            <ir-date-select
              label="Date"
              date={this.formData.date}
              minDate={minAllowedDate}
              emitEmptyDate={true}
              onDateChanged={event => {
                this.updateFormData({
                  date: event.detail.start ? event.detail.start.format(DATE_INPUT_FORMAT) : '',
                });
              }}
            ></ir-date-select>
          </ir-validator>
        </div>
        {withTaxes ? (
          <div class="amount-tax-group">
            <span class="amount-tax-group__label">Amount (including taxes)</span>
            <div class="amount-tax-group__row">
              <ir-validator class="amount-tax-group__amount" schema={amountFieldSchema} value={this.formData.amount} valueEvent="text-change input-change">
                <ir-input
                  label="Amount (including taxes)"
                  mask="price"
                  value={this.formData.amount}
                  onText-change={(event: CustomEvent<string>) => {
                    this.updateFormData({ amount: event.detail ?? '' });
                  }}
                >
                  <span slot="start">{this.currencySymbol}</span>
                </ir-input>
              </ir-validator>
              <ir-validator schema={taxIdFieldSchema} value={this.formData.taxId} valueEvent="change">
                <wa-select
                  size="small"
                  placeholder="Tax"
                  value={this.formData.taxId}
                  onchange={event => {
                    this.updateFormData({ taxId: (event.target as HTMLSelectElement).value });
                  }}
                >
                  <wa-option value="N/A" label="Not Applicable">
                    Not Applicable
                  </wa-option>
                  {this.taxOptions.map(tax => (
                    <wa-option key={tax.id} label={tax.label} value={tax.id}>
                      {tax.label}
                    </wa-option>
                  ))}
                </wa-select>
              </ir-validator>
            </div>
          </div>
        ) : (
          <div class="transaction-form__field">
            <ir-validator schema={amountFieldSchema} value={this.formData.amount} valueEvent="text-change input-change">
              <ir-input
                label="Amount"
                mask="price"
                value={this.formData.amount}
                required
                onText-change={(event: CustomEvent<string>) => {
                  this.updateFormData({ amount: event.detail ?? '' });
                }}
              >
                <span slot="start">{this.currencySymbol}</span>
              </ir-input>
            </ir-validator>
          </div>
        )}
      </Fragment>
    );
  }

  private renderEntryTypeField() {
    return (
      <div class="transaction-form__field transaction-form__field--full-width">
        <ir-validator schema={entryTypeFieldSchema} value={this.formData.entryType ?? ''} valueEvent="change">
          <wa-radio-group
            label="Entry Type"
            orientation="horizontal"
            size="small"
            value={this.formData.entryType ?? ''}
            onchange={event => {
              this.updateFormData({ entryType: (event.target as HTMLInputElement).value as EntryType });
            }}
          >
            <wa-radio value="CR" appearance="button" class="transaction-form__field__entry-type --credit">
              Credit
            </wa-radio>
            <wa-radio value="DB" appearance="button" class="transaction-form__field__entry-type --debit">
              Debit
            </wa-radio>
          </wa-radio-group>
        </ir-validator>
      </div>
    );
  }

  private renderOpeningBalanceFields() {
    return <Fragment>{this.renderEntryTypeField()}</Fragment>;
  }

  private renderPaymentFields() {
    const isOnAccount = this.formData.onAccount;

    return (
      <Fragment>
        {/* ── Payment Details ────────────────────────── */}
        <div class="payment-section">
          <div class="transaction-form__field">
            <ir-validator schema={paymentMethodCodeFieldSchema} value={this.formData.payment_method?.code ?? ''} valueEvent="change">
              <wa-select
                size="small"
                label="Payment method"
                placeholder="Select method…"
                value={this.formData.payment_method?.code ?? ''}
                onwa-show={event => this.stopEventPropagation(event)}
                onwa-hide={event => this.stopEventPropagation(event)}
                onchange={event => {
                  this.stopEventPropagation(event);
                  this.handlePaymentMethodDropdownChange((event.target as HTMLSelectElement).value);
                }}
              >
                <wa-option value="">Select method…</wa-option>
                {this.paymentEntries?.methods?.map(method => (
                  <wa-option key={method.CODE_NAME} label={method.CODE_VALUE_EN} value={method.CODE_NAME}>
                    {getEntryValue({ entry: method, language: this.language })}
                  </wa-option>
                ))}
              </wa-select>
            </ir-validator>
          </div>
        </div>

        {/* ── Payment Application ─────────────────────── */}
        <div class="payment-section">
          <wa-radio-group
            label="Apply to"
            size="small"
            orientation="horizontal"
            value={isOnAccount ? 'on-account' : 'apply-to-invoice'}
            onchange={e => {
              const val = (e.target as HTMLInputElement).value;
              this.updateFormData({ onAccount: val === 'on-account', invoiceId: val === 'on-account' ? undefined : this.formData.invoiceId });
            }}
          >
            <wa-radio appearance="button" value="on-account">
              On Account
            </wa-radio>
            <wa-radio appearance="button" value="apply-to-invoice">
              Close Invoices
            </wa-radio>
          </wa-radio-group>

          {/* Invoice selector — revealed when "Apply to Invoice" is chosen */}
          {!isOnAccount && (
            <div class="transaction-form__field payment-invoice-select">
              <wa-select
                label="Outstanding Invoice"
                size="small"
                placeholder="Search invoices…"
                value={this.formData.invoiceId ?? ''}
                onwa-show={event => this.stopEventPropagation(event)}
                onwa-hide={event => this.stopEventPropagation(event)}
                onchange={event => {
                  this.stopEventPropagation(event);
                  this.updateFormData({ invoiceId: (event.target as HTMLSelectElement).value || undefined });
                }}
              >
                <wa-option value="">No invoice linked</wa-option>
                {this.unpaidInvoiceOptions.length === 0 && (
                  <wa-option value="" disabled>
                    No outstanding invoices
                  </wa-option>
                )}
                {this.unpaidInvoiceOptions.map(invoice => (
                  <wa-option key={invoice.id} value={invoice.id}>
                    {invoice.label}
                  </wa-option>
                ))}
              </wa-select>
            </div>
          )}
        </div>
      </Fragment>
    );
  }

  private renderManualChargeFields() {
    return null;
    // return (
    //   <div class="transaction-form__field">
    //     <ir-validator schema={serviceCategoryFieldSchema} value={this.formData.serviceCategoryId ?? ''} valueEvent="change">
    //       <wa-select
    //         label="Service Category"
    //         size="small"
    //         value={this.formData.serviceCategoryId ?? ''}
    //         required
    //         onchange={event => {
    //           this.updateFormData({ serviceCategoryId: (event.target as HTMLSelectElement).value || undefined });
    //         }}
    //       >
    //         <wa-option value="">Select a service category</wa-option>
    //         {this.serviceCategoryOptions.map(category => (
    //           <wa-option key={category.id} value={category.id}>
    //             {category.label}
    //           </wa-option>
    //         ))}
    //       </wa-select>
    //     </ir-validator>
    //   </div>
    // );
  }

  private renderAdjustmentFields() {
    return (
      <Fragment>
        {this.renderEntryTypeField()}

        <div class="transaction-form__field">
          <ir-validator schema={linkTypeFieldSchema} value={this.formData.linkType ?? 'NONE'} valueEvent="change">
            <wa-select
              label="Link Type"
              size="small"
              value={this.formData.linkType ?? 'NONE'}
              onchange={event => {
                const linkType = (event.target as HTMLSelectElement).value as LinkType;
                this.updateFormData({
                  linkType,
                  linkedId: linkType === 'NONE' ? undefined : this.formData.linkedId,
                });
              }}
            >
              {LINK_TYPES.map(linkType => (
                <wa-option key={linkType} value={linkType}>
                  {linkType}
                </wa-option>
              ))}
            </wa-select>
          </ir-validator>
        </div>

        {this.formData.linkType !== 'NONE' && (
          <div class="transaction-form__field">
            <wa-select
              label="Linked Record"
              size="small"
              value={this.formData.linkedId ?? ''}
              onchange={event => {
                this.updateFormData({ linkedId: (event.target as HTMLSelectElement).value || undefined });
              }}
            >
              <wa-option value="">No linked record</wa-option>
              {this.linkedIdOptions.map(option => (
                <wa-option key={option.id} value={option.id}>
                  {option.label}
                </wa-option>
              ))}
            </wa-select>
          </div>
        )}
      </Fragment>
    );
  }

  private renderFiscalNoteFields() {
    return (
      <Fragment>
        <div class="transaction-form__field">
          <ir-validator schema={invoiceIdRequiredFieldSchema} value={this.formData.invoiceId ?? ''} valueEvent="change">
            <wa-select
              label="Invoice"
              size="small"
              required
              value={this.formData.invoiceId ?? ''}
              onchange={event => {
                this.updateFormData({ invoiceId: (event.target as HTMLSelectElement).value || undefined });
              }}
            >
              <wa-option value="">Select invoice</wa-option>
              {this.unpaidInvoiceOptions.map(invoice => (
                <wa-option key={invoice.id} value={invoice.id}>
                  {invoice.label}
                </wa-option>
              ))}
            </wa-select>
          </ir-validator>
        </div>
      </Fragment>
    );
  }

  private renderConditionalFields() {
    switch (this.formData.transactionType) {
      case 'OB':
        return this.renderOpeningBalanceFields();
      case 'PAY':
        return this.renderPaymentFields();
      case 'DB':
        return this.renderManualChargeFields();
      case 'ADJ':
        return this.renderAdjustmentFields();
      case 'CN':
      case 'DN':
        return this.renderFiscalNoteFields();
      default:
        return null;
    }
  }

  render() {
    if (this.isLoading) {
      return (
        <div class="dialog__loader-container">
          <ir-spinner></ir-spinner>
        </div>
      );
    }
    return (
      <form id={this.formId} class="transaction-form" onSubmit={this.handleSubmit} novalidate>
        {this.renderCommonFields(!['OB', 'PAY'].includes(this.formData.transactionType))}
        {this.renderConditionalFields()}
        <ir-input label="Reference"></ir-input>
      </form>
    );
  }
}
